import { SolidComponent } from '@/type';
import { cn } from '@/utils/cn';
import { AnimationConfig, renderCSSAnimation } from '@/utils/helper';
import { conditionalRender } from '@/utils/hoc';
import X from 'lucide-solid/icons/x';

import {
  Component,
  createEffect,
  createSignal,
  createUniqueId,
  mergeProps,
  on,
  onCleanup,
  Show,
} from 'solid-js';
import { ZIndex, ZIndexType } from '../z-index';

export type ModalType = {
  onClose: () => void;
  width?: string;
  closeOnOutsideClick?: boolean;
  closeOnEsc?: boolean;
  closable?: boolean;
  header?: SolidComponent;
  body?: SolidComponent;
  footer?: SolidComponent;
  open?: boolean;
  mask?: boolean | { enabled: boolean; blur: boolean };
  class?: Partial<
    Record<'wrapper' | 'modal' | 'header' | 'body' | 'footer' | 'closeButton', string>
  >;
  preRender?: boolean;
  animate?: Omit<AnimationConfig, 'name'> & {
    name: AnimateType;
  };
};

// Only opacity-based animations are safe to use on the modal box directly
// because transform-based animations create a new containing block for
// position:fixed descendants, which breaks fixed positioning inside body slots.
// Transform animations are applied on a sibling overlay div instead.
type AnimateType =
  | 'none'
  | 'lightSpeedInRight'
  | 'lightSpeedInLeft'
  | 'fadeIn'
  | 'fadeInLeft'
  | 'fadeInRight'
  | 'fadeInDown'
  | 'fadeInUp'
  | 'bounceIn'
  | 'scaleInCenter'
  | 'slideInFwdCenter'
  | 'slideInBck'
  | 'tiltIn'
  | 'swingInRightBck'
  | 'puffInCenter'
  | 'scaleInBl';

// Animations that use transform in their keyframes — these create a containing
// block for position:fixed elements during the animation. They must NOT be
// placed on any ancestor of body content.
const TRANSFORM_ANIMATIONS = new Set<AnimateType>([
  'lightSpeedInRight',
  'lightSpeedInLeft',
  'fadeInLeft',
  'fadeInRight',
  'fadeInDown',
  'fadeInUp',
  'bounceIn',
  'scaleInCenter',
  'slideInFwdCenter',
  'slideInBck',
  'tiltIn',
  'swingInRightBck',
  'puffInCenter',
  'scaleInBl',
]);

// Track active modals for overlay logic (only topmost modal shows mask)
const [modalIds, setModalIds] = createSignal<string[]>([]);
function popModalId() {
  const newArr = modalIds().slice();
  newArr.pop();
  setModalIds(newArr);
}

// Global ESC key handler — single listener shared across all modal instances
const modalCloseCallbacks = new Map<string, () => void>();

function globalKeyDownHandler(e: KeyboardEvent) {
  if (e.key !== 'Escape') return;
  const topId = modalIds().at(-1);
  if (topId) modalCloseCallbacks.get(topId)?.();
}

function registerModalCallback(id: string, cb: () => void) {
  if (modalCloseCallbacks.size === 0) {
    document.addEventListener('keydown', globalKeyDownHandler);
  }
  modalCloseCallbacks.set(id, cb);
}

function unregisterModalCallback(id: string) {
  modalCloseCallbacks.delete(id);
  if (modalCloseCallbacks.size === 0) {
    document.removeEventListener('keydown', globalKeyDownHandler);
  }
}

const ComponentModal: Component<ModalType> = p => {
  p = mergeProps(
    {
      closeOnOutsideClick: true,
      closeOnEsc: true,
      open: true,
      onClose: () => {},
      closable: true,
      preRender: false,
      animate: {
        name: 'puffInCenter',
        duration: '300ms',
      },
      mask: true,
    } as ModalType,
    p,
  );

  const modalId = createUniqueId();

  onCleanup(function unregisterModal() {
    unregisterModalCallback(modalId);
    if (modalId === modalIds().at(-1)) {
      popModalId();
    }
  });

  // Manage modalIds stack for overlay logic
  createEffect(
    on(
      () => p.open,
      open => {
        if (open) {
          if (modalId !== modalIds().at(-1)) {
            setModalIds([...modalIds(), modalId]);
          }
          registerModalCallback(modalId, () => {
            if (p.closeOnEsc) p.onClose();
          });
        } else {
          unregisterModalCallback(modalId);
          if (modalId === modalIds().at(-1)) {
            popModalId();
          }
        }
      },
    ),
  );

  const renderMaskEnabled = (): boolean => {
    if (!p.open) return false;
    if (modalId !== modalIds().at(-1)) return false;
    if (p.mask === false) return false;
    if (typeof p.mask === 'object' && p.mask?.enabled === false) return false;
    return true;
  };

  const renderMaskClass = (): string => {
    if (typeof p.mask === 'object' && p.mask?.blur === false) {
      return 'bg-modal-overlay';
    }
    return 'bg-modal-overlay backdrop-blur-[5px]';
  };

  const animName = (): AnimateType => p.animate?.name ?? 'none';
  const isTransformAnim = () => TRANSFORM_ANIMATIONS.has(animName());

  // For transform-based animations: rendered on a sibling absolutely-positioned
  // overlay div that visually matches the modal box but is NOT an ancestor of
  // body content. This completely avoids the containing-block issue.
  // For opacity-only animations (fadeIn): applied directly on the modal box.
  const renderModalBoxAnim = () => {
    if (!isTransformAnim() && animName() !== 'none') {
      return { animation: renderCSSAnimation(p.animate!) };
    }
    return {};
  };

  const renderOverlayAnim = () => {
    if (isTransformAnim()) {
      return { animation: renderCSSAnimation(p.animate!) };
    }
    return {};
  };

  const renderBoxStyle = () => {
    const style: Record<string, any> = {};
    if (p.width) {
      style['width'] = p.width;
      style['min-width'] = p.width;
    }
    return style;
  };

  // Overlay: a visually identical copy of the modal box that carries the
  // transform animation. It sits on top of the real modal box via absolute
  // positioning. Once animation ends it is hidden and the real box is shown.
  const [overlayDone, setOverlayDone] = createSignal(false);
  const handleOverlayAnimEnd = () => setOverlayDone(true);

  // Reset overlayDone each time modal re-opens so transform animation replays.
  createEffect(
    on(
      () => p.open,
      open => {
        if (open) setOverlayDone(false);
      },
    ),
  );

  // Real modal box becomes visible only after transform animation finishes
  // (to avoid showing both simultaneously).
  const boxVisible = () => !isTransformAnim() || overlayDone();

  const handleBackdropClick = () => {
    if (p.closeOnOutsideClick) {
      p.onClose();
    }
  };

  return (
    <ZIndex
      type={ZIndexType.MODAL}
      open={p.open ?? false}
      blockScroll
      preRender={p.preRender}
      position={{ inset: '0' }}
      class={cn('mo01', p.class?.wrapper)}
    >
      {/* Backdrop overlay — only for topmost modal */}
      <Show when={renderMaskEnabled()}>
        <div class={cn('mo02', renderMaskClass())} onClick={handleBackdropClick} />
      </Show>

      {/* Invisible hit area for outside-click when mask is disabled */}
      <Show when={!renderMaskEnabled() && p.closeOnOutsideClick}>
        <div class="mo02" onClick={handleBackdropClick} />
      </Show>

      {/* Wrapper: flex item căn giữa bởi parent. Kích thước khớp real box.
          Overlay absolute bên trong → luôn cùng vị trí & kích thước với real box. */}
      <div class="mo03" onClick={e => e.stopPropagation()}>
        {/* === Transform animation approach ===
            Overlay là visual clone với animation transform, positioned absolute
            bên trong wrapper → khớp 100% kích thước/vị trí với real box.
            Giữ body content thoát khỏi transform ancestor. */}
        <Show when={isTransformAnim() && !overlayDone()}>
          <div
            class={cn('mo04', p.class?.modal)}
            style={{ ...renderBoxStyle(), ...renderOverlayAnim() }}
            onAnimationEnd={handleOverlayAnimEnd}
            aria-hidden="true"
          />
        </Show>

        {/* === Real modal box ===
            Dùng opacity animation (an toàn) hoặc không animation.
            Body content luôn thoát khỏi transform ancestor. */}
        <div
          class={cn('mo05', p.class?.modal)}
          style={{
            ...renderModalBoxAnim(),
            ...renderBoxStyle(),
            visibility: boxVisible() ? 'visible' : 'hidden',
          }}
        >
          {p.closable && (
            <button class={cn('mo06', p.class?.closeButton)} onClick={p.onClose} aria-label="Close">
              <X size={16} />
            </button>
          )}

          <div class={cn('mo-header', p.class?.header)}>
            <Show when={p.header} fallback={<div class="mo07">Modal ID: {modalId}</div>}>
              {p.header as Element}
            </Show>
          </div>

          <div class={cn('mo08', p.class?.body)}>
            <Show when={p.body}>{p.body as Element}</Show>
          </div>

          <Show when={p.footer}>
            <div class={cn('mo-footer', p.class?.footer)}>{p.footer as Element}</div>
          </Show>
        </div>
      </div>
    </ZIndex>
  );
};

export const Modal = conditionalRender(ComponentModal, { preRender: 'preRender', when: 'open' });

export { ComponentModal };
